            for child_key in list(node.children.keys()):
                if self._search(node.children[child_key], pattern, index + 1):
                    return True
            return False
        else:
            child = node.children.get(ch)
            if child is None:
                return False
            return self._search(child, pattern, index + 1)

    def get_all_words(self):
        """Return all inserted words."""
        return self._words[:]

    def starts_with(self, prefix):
        """Return True if any word starts with the given prefix."""
        node = self
        for ch in prefix:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return True

    def delete(self, word):
        """Delete a word from the trie."""
        if word not in self._words:
            return
        self._words.remove(word)
        self._delete(self, word, 0)

    def _delete(self, node, word, index):
        if index == len(word):
            node.is_end = False
            return

        ch = word[index]
        if ch not in node.children:
            return

        self._delete(node.children[ch], word, index + 1)
        child_node = node.children[ch]

        # Prune empty nodes: if child has no children and is not end of another word
        if not child_node.children and not child_node.is_end:
            del node.children[ch]
